        if (_updatedValue == null) {
            value = _deserializer.deserialize(_parser, _context);
        } else{
            _deserializer.deserialize(_parser, _context, _updatedValue);
            value = _updatedValue;
        }
        nextState = STATE_MAY_HAVE_VALUE;
        return value;
